examples.code:
const usuarios = [
  { id: 1, nombre: 'Ana' },
  { id: 2, nombre: 'Luis' },
  { id: 3, nombre: 'Marta' }
];

const usuario = usuarios.find(u => u.id === 2);
console.log(usuario); // { id: 2, nombre: 'Luis' }

const noExiste = usuarios.find(u => u.id === 99);
console.log(noExiste); // undefined

const productos = [
  { nombre: 'A', stock: 0 },
  { nombre: 'B', stock: 5 },
  { nombre: 'C', stock: 0 }
];

const hayEnStock = productos.some(p => p.stock > 0);
console.log(hayEnStock); // true

const todosSinStock = productos.every(p => p.stock === 0);
console.log(todosSinStock); // false

const edades = [20, 22, 18, 25, 30];

const menorDeEdad = edades.find(edad => edad < 18);
console.log(menorDeEdad); // undefined (no hay ninguno)

const todosMayores = edades.every(edad => edad >= 18);
console.log(todosMayores); // true

const hayMayorDe28 = edades.some(edad => edad > 28);
console.log(hayMayorDe28); // true

